const std = @import("std");
const asn1 = std.crypto.asn1;

// has the limitation that it can only encode up to 64-bit integers
pub fn encodeLength(writer: anytype, value: u64) !void {
    const n_bytes = b: {
        var i: u8 = 0;
        var l: usize = value;
        while (l != 0) {
            l >>= 8;
            i += 1;
        }
        break :b i;
    };

    if (n_bytes > 1) {
        const long_form = (1 << 7) + n_bytes;
        try writer.writeAll(std.mem.asBytes(&std.mem.nativeToBig(u8, long_form)));
    }

    switch (n_bytes) {
        0...1 => try writer.writeAll(std.mem.asBytes(&std.mem.nativeToBig(u8, @intCast(value)))),
        2 => try writer.writeAll(std.mem.asBytes(&std.mem.nativeToBig(u16, @intCast(value)))),
        3 => try writer.writeAll(std.mem.asBytes(&std.mem.nativeToBig(u32, @intCast(value)))),
        4 => try writer.writeAll(std.mem.asBytes(&std.mem.nativeToBig(u64, @intCast(value)))),
        else => unreachable,
    }
}

